CODE_EXAMPLE:
class GuessStatisticsMessage {
    private String number;
    private String verb;
    private String pluralModifier;

    public String make(char candidate, int count) {
        createPluralDependentMessageParts(count);
        return String.format("There %s %s %s%s", verb, number, candidate, pluralModifier);
    }

    private void createPluralDependentMessageParts(int count) {
        if (count == 0)       { number = "no";                    verb = "are"; pluralModifier = "s"; }
        else if (count == 1)  { number = "1";                     verb = "is";  pluralModifier = ""; }
        else                  { number = Integer.toString(count);  verb = "are"; pluralModifier = "s"; }
    }
}

UNIT_TEST_EXAMPLE:
@Test
public void make_formatsZeroCount() {
    GuessStatisticsMessage msg = new GuessStatisticsMessage();
    assertEquals("There are no xs", msg.make('x', 0));
}

@Test
public void make_formatsOneCount() {
    GuessStatisticsMessage msg = new GuessStatisticsMessage();
    assertEquals("There is 1 x", msg.make('x', 1));
}
